import React, { useState, useEffect } from "react";
import axios from "axios";
import EmailEditor from "react-email-editor"; // ✨ WYSIWYG editor imported
// npm install react-email-editor

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [template, setTemplate] = useState("promo");
  const [htmlContent, setHtmlContent] = useState("");
  const [targetGroup, setTargetGroup] = useState("subscribed");
  const [scheduleDate, setScheduleDate] = useState("");
  const [history, setHistory] = useState([]);
  const [sending, setSending] = useState(false);
  const token = localStorage.getItem("adminToken");

  const fetchHistory = async () => {
    const res = await axios.get("http://localhost:5000/api/email/history", {
      headers: { Authorization: `Bearer ${token}` },
    });
    setHistory(res.data);
  };

  const sendEmail = async () => {
    setSending(true);

    const editorHtml = htmlContent || "<p>(Không có nội dung)</p>";

    const res = await axios.post(
      "http://localhost:5000/api/email/send",
      {
        subject,
        html: editorHtml,
        group: targetGroup,
        schedule: scheduleDate || null
      },
      { headers: { Authorization: `Bearer ${token}` } }
    );

    alert(res.data.message);
    setSending(false);
    fetchHistory();
  };

  useEffect(() => {
    fetchHistory();
  }, []);

  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold text-[#e06c7f] mb-8">📩 Email Marketing Pro</h1>

      <div className="grid grid-cols-2 gap-6">
        {/* LEFT COLUMN */}
        <div className="bg-white shadow-md p-6 rounded-xl border">

          <label className="font-medium">Tiêu đề Email</label>
          <input
            className="w-full border p-3 rounded-lg mb-4"
            value={subject}
            onChange={(e) => setSubject(e.target.value)}
          />

          <label className="font-medium">Nhóm người nhận 👥</label>
          <select
            className="w-full border p-3 rounded-lg mb-4"
            value={targetGroup}
            onChange={(e) => setTargetGroup(e.target.value)}
          >
            <option value="all">📢 Tất cả người dùng</option>
            <option value="subscribed">📰 Đã đăng ký nhận email</option>
            <option value="vip">👑 Khách hàng VIP</option>
          </select>

          <label className="font-medium">Lên lịch gửi ⏰ (không bắt buộc)</label>
          <input
            type="datetime-local"
            className="w-full border p-3 rounded-lg mb-4"
            onChange={(e) => setScheduleDate(e.target.value)}
          />

          {/* WYSIWYG EDITOR */}
          <label className="font-medium">💌 Soạn email (WYSIWYG editor)</label>
          <textarea
            value={htmlContent}
            onChange={(e) => setHtmlContent(e.target.value)}
            className="w-full h-40 border p-3 rounded-lg mb-4"
          />

          <button
            onClick={sendEmail}
            disabled={sending}
            className="w-full py-3 bg-[#e06c7f] text-white rounded-lg font-semibold"
          >
            {sending ? "⏳ Đang gửi..." : "📨 Gửi Email"}
          </button>
        </div>

        {/* RIGHT COLUMN */}
        <div>
          {/* Preview */}
          <h2 className="text-lg font-semibold mb-3">🖼 Preview Email</h2>
          <div
            className="bg-white border rounded-lg p-4 shadow-inner h-64 overflow-auto"
            dangerouslySetInnerHTML={{ __html: htmlContent || "<p>Nhập nội dung ở ô bên trái...</p>" }}
          />

          {/* HISTORY */}
          <h2 className="text-lg font-semibold mt-8 mb-2">📜 Lịch sử email đã gửi</h2>
          <div className="bg-white border rounded-lg p-4 shadow-md max-h-64 overflow-auto">
            {history.length === 0 && <p className="text-gray-500">Chưa có email nào</p>}

            {history.map((item) => (
              <div key={item._id} className="border-b py-2">
                <strong>{item.subject}</strong>
                <p className="text-sm text-gray-600">{item.dateSent}</p>
                <p className="text-xs text-gray-500">Nhóm: {item.group}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SendEmailPage;
